{
  "planCode": "pro-monthly",
  "name": "Pro Monthly",
  "stripePriceId": "price_xxxxx",
  "features": {
    "rbac": true,
    "auditLogs": true,
    "apiAccess": true,
    "automationWorkers": false,
    "advancedSecurity": false,
    "sso": false
  },
  "limits": {
    "maxUsers": 50,
    "maxStorageGB": 100,
    "maxApiCallsPerMonth": 10000,
    "auditLogRetentionDays": 90
  },
  "metadata": {}
}

{
  "templateId": "{{template_id}}",
  "name": "Daily DSR — Every Evening 6PM",
  "status": "active",
  "scope": {
    "type": "TENANT"
  },
  "cadence": "DAILY",
  "timezone": "Asia/Kolkata",
  "runAt": {
    "hour": 18,
    "minute": 0
  },
  "delivery": {
    "channels": ["IN_APP", "EMAIL"],
    "recipients": {
      "userIds": [],
      "emails": ["admin@example.com"]
    },
    "subjectTemplate": "Daily Summary Report — {{date}}",
    "messageTemplate": "Please find attached the daily summary report."
  },
  "output": {
    "formats": ["PDF"],
    "includeBranding": true
  }
}

{
  "reportType": "DSR",
  "departmentId": "{{department_id}}",
  "templateId": "{{report_template_id}}",
  "period": {
    "startDate": "2026-03-08T00:00:00.000Z",
    "endDate": "2026-03-08T23:59:59.999Z"
  },
  "contentTitle": "Daily Status",
  "description": "Daily report",
  "content": [
    {
      "fieldId": "goal",
      "label": "Goal",
      "type": "textarea",
      "value": "Implemented Redis cache layer"
    },
    {
      "fieldId": "blockers",
      "label": "Blockers",
      "type": "textarea",
      "value": "Redis reconnection issue"
    }
  ],
  "goalIds": [
    "{{work_goal_id}}"
  ]
}
